// Normalize output from either AI branch
const item = $input.all()[0];
const body = item.json;
const script = body.choices?.[0]?.message?.content || '';
const topic = $('Webhook Trigger').item.json.body.content || 'Finance Topic';
const inputType = $('Webhook Trigger').item.json.body.input_type || 'topic';

return [{ json: { script, topic, inputType } }];

// Parse scenes JSON from AI response
const item = $input.all()[0];
const raw = item.json.choices?.[0]?.message?.content || '[]';
const script = item.json.script || $('Code: Normalize Script').item.json.script;
const topic = item.json.topic || $('Code: Normalize Script').item.json.topic;

let scenes = [];
try {
  // Strip markdown code fences if present
  const cleaned = raw.replace(/```json|```/g, '').trim();
  scenes = JSON.parse(cleaned);
} catch(e) {
  scenes = [{ scene_number: 1, scene_label: 'Full Script', scene_text: script }];
}

// Pass script + topic through
return scenes.map(s => ({ json: { ...s, script, topic } }));

