// Collect all scene prompts into a final response object
const items = $input.all();
if (!items.length) return [{ json: { error: 'No scenes generated' } }];

const first = items[0].json;
const script = first.script || '';
const topic = first.topic || 'Finance Topic';

const scenes = items.map(item => ({
  scene_number: item.json.scene_number,
  scene_label: item.json.scene_label || '',
  scene_text: item.json.scene_text || '',
  image_prompt: item.json.choices?.[0]?.message?.content || ''
}));

return [{ json: { topic, script, scenes } }];
